import dspy

def search_wiki(query: str) -> str:
    """Search Wikipedia for a short summary."""
    import wikipedia
    try:
        return wikipedia.summary(query, sentences=2)
    except Exception:
        return "No result found."

class ResearchQuestion(dspy.Signature):
    """Answer a research question using available tools."""
    question: str = dspy.InputField()
    answer: str = dspy.OutputField()

react_agent = dspy.ReAct(ResearchQuestion, tools=[search_wiki])
result = react_agent(question="Who invented the transistor and in what year?")
print(result.answer)
